submit.typescript:
import { postChatgptRunAskFailure } from "./emit";

/** Phase: submit — deferred click so React/ChatGPT picks up input state. */
export function scheduleSubmitChatgpt(startedAt: string): void {
  window.setTimeout(() => {
    const submitButton = document.querySelector(
      "#composer-submit-button"
    ) as HTMLButtonElement | null;
    if (!submitButton) {
      postChatgptRunAskFailure("no_submit_button", startedAt);
      return;
    }
    submitButton.click();
  }, 100);
}

run_ask.typescript:
import { fillChatgptComposer } from "./fill";
import { scheduleSubmitChatgpt } from "./submit";
import { postChatgptRunAskFailure } from "./emit";
import { resolveChatgptComposer } from "./resolveComposer";

/**
 * Phases: resolve_composer → fill → submit.
 * wait_capture = SSE in `capture.ts`; emit success via `emit.ts` there.
 */
export function runChatgptAsk(text: string): void {
  const startedAt = new Date().toISOString();
  const c = resolveChatgptComposer();
  if (!c) {
    postChatgptRunAskFailure("dom_not_ready", startedAt);
    return;
  }
  const trimmed = typeof text === "string" ? text.trim() : "";
  if (!trimmed) {
    postChatgptRunAskFailure("missing_prompt", startedAt);
    return;
  }
  fillChatgptComposer(c, trimmed);
  scheduleSubmitChatgpt(startedAt);
}

wait_capture.typescript:
import { chatgptPostToContent } from "./emit";

const MAX_SSE_SAMPLES = 48;
const MAX_DATA_LEN = 2000;

/**
 * Phase: wait_capture — ChatGPT wraps `fetch`, reads SSE until the stream ends,
 * then emit via `chatgptPostToContent` (success path).
 */
export function installChatgptSseFetchCapture(): void {
  const originalFetch = window.fetch;

  window.fetch = async function (...args) {
    const response = await originalFetch(...args);

    const contentType = response.headers.get("content-type") || "";
    if (!contentType.includes("text/event-stream")) {
      return response;
    }

    const clone = response.clone();
    const reader = clone.body?.getReader();
    const decoder = new TextDecoder("utf-8");

    let buffer = "";
    let fullAssistantMessage = "";
    let deltaPatchCount = 0;
    const sseSamples: { event: string; data: string }[] = [];
    const streamSignals: unknown[] = [];

    function pushSample(eventName: string | null, dataStr: string) {
      if (sseSamples.length >= MAX_SSE_SAMPLES) sseSamples.shift();
      sseSamples.push({
        event: eventName ?? "(default)",
        data: String(dataStr).slice(0, MAX_DATA_LEN),
      });
    }

    async function readStream() {
      while (true) {
        if (reader === undefined) return response;
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });

        const parts = buffer.split(/\r?\n\r?\n/);
        buffer = parts.pop() as string;

        for (let part of parts) {
          part = part.trim();
          if (!part) continue;

          const lines = part.split(/\r?\n/);

          let eventName: string | null = null;
          const dataLines: string[] = [];

          for (const line of lines) {
            if (line.startsWith("event:")) {
              eventName = line.substring("event:".length).trim();
            } else if (line.startsWith("data:")) {
              dataLines.push(line.substring("data:".length).trim());
            }
          }

          const dataStr = dataLines.join("\n");
          pushSample(eventName, dataStr);

          if (eventName === "delta" || eventName === "delta_encoding") {
            try {
              const obj = JSON.parse(dataStr);

              if (eventName === "delta") {
                if (Array.isArray(obj.v)) {
                  for (const patch of obj.v) {
                    if (patch.p && patch.o === "append" && patch.v) {
                      if (patch.p.includes("/message/content/parts")) {
                        fullAssistantMessage += patch.v;
                        deltaPatchCount += 1;
                      }
                    }
                  }
                }
              }
            } catch (err) {
              console.warn("Could not parse SSE data JSON:", dataStr, err);
              fullAssistantMessage += dataStr;
            }
          } else if (eventName === null) {
            try {
              const obj = JSON.parse(dataStr);
              if (obj && typeof obj === "object") {
                if (obj.type === "message_stream_complete") {
                  streamSignals.push({
                    type: "message_stream_complete",
                    snippet: JSON.stringify(obj).slice(0, 4000),
                  });
                } else {
                  streamSignals.push({
                    type: obj.type ?? "unknown",
                    snippet: JSON.stringify(obj).slice(0, 2000),
                  });
                }
              }
            } catch {
              // not JSON
            }
          }
        }
      }

      const assistantText = fullAssistantMessage.trim();

      chatgptPostToContent({
        assistantText,
        page: {
          href: typeof location !== "undefined" ? location.href : "",
          title: typeof document !== "undefined" ? document.title : "",
        },
        capture: {
          completedAt: new Date().toISOString(),
          deltaPatchCount,
          sseSampleCount: sseSamples.length,
          sseSamples,
          streamSignals: streamSignals.slice(-12),
        },
      });
    }
    readStream().catch((err) => console.error("SSE read error:", err));
    return response;
  };
}

emit.typescript:
import { CHATGPT_SRC_PAGE } from "./constants";

/** Phase: emit — postMessage envelope to content (`version` + `source` + payload). */
export function chatgptPostToContent(payload: Record<string, unknown>): void {
  window.postMessage(
    {
      data: {
        version: 1,
        source: CHATGPT_SRC_PAGE,
        ...payload,
      },
    },
    "*"
  );
}

/** Emit failure before SSE wait_capture (early resolve / submit exit). */
export function postChatgptRunAskFailure(
  reason: string,
  startedAt: string
): void {
  chatgptPostToContent({
    assistantText: "",
    page: {
      href: typeof location !== "undefined" ? location.href : "",
      title: typeof document !== "undefined" ? document.title : "",
    },
    capture: {
      startedAt,
      completedAt: new Date().toISOString(),
      ok: false,
      reason,
    },
  });
}

dom_helpers.typescript:
/** Inlined so `chatgpt-page.js` stays a single classic script (no shared chunk `import`). */

export function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

export async function waitFor<T>(
  fn: () => T | null | undefined,
  timeoutMs: number,
  intervalMs = 120
): Promise<T | null> {
  const end = Date.now() + timeoutMs;
  while (Date.now() < end) {
    const v = fn();
    if (v) return v;
    await sleep(intervalMs);
  }
  return null;
}

export function isProbablyVisible(el: HTMLElement): boolean {
  if (!el.isConnected) return false;
  const st = window.getComputedStyle(el);
  if (st.display === "none" || st.visibility === "hidden") return false;
  if (document.visibilityState !== "visible") return true;
  const r = el.getBoundingClientRect();
  return r.width >= 2 && r.height >= 2;
}

export async function waitForPaintTick(): Promise<void> {
  if (document.visibilityState !== "visible") {
    await sleep(50);
    return;
  }
  await new Promise<void>((r) =>
    requestAnimationFrame(() => requestAnimationFrame(() => r()))
  );
}

/** Last matching node in document order (bottom composer after multi-turn chat). */
export function lastMatchingElement(
  selector: string,
  pred: (el: HTMLElement) => boolean
): HTMLElement | null {
  const list = document.querySelectorAll(selector);
  for (let i = list.length - 1; i >= 0; i--) {
    const el = list[i];
    if (el instanceof HTMLElement && pred(el)) return el;
  }
  return null;
}

