resolve_composer.typescript:
import { isProbablyVisible, lastMatchingElement } from "./domHelpers";

/**
 * Phase: resolve_composer — Gemini Quill / rich-textarea (light + shadow DOM).
 */
export function findGeminiEditableRoot(): HTMLElement | null {
  const qlPred = (el: HTMLElement) =>
    !el.classList.contains("ql-clipboard") && isProbablyVisible(el);

  const scopedSelectors = [
    '[data-node-type="input-area"] rich-textarea div.ql-editor[contenteditable="true"]',
    '[data-node-type="input-area"] div.ql-editor[contenteditable="true"]',
    "footer rich-textarea div.ql-editor[contenteditable='true']",
    'footer div.ql-editor[contenteditable="true"]',
  ];
  for (const sel of scopedSelectors) {
    const hit = lastMatchingElement(sel, qlPred);
    if (hit) return hit;
  }

  const qlInRich = lastMatchingElement(
    "rich-textarea div.ql-editor[contenteditable='true'], rich-textarea div.ql-editor[contenteditable=\"true\"]",
    qlPred
  );
  if (qlInRich) return qlInRich;

  const richList = document.querySelectorAll("rich-textarea");
  for (let i = richList.length - 1; i >= 0; i--) {
    const rich = richList[i] as HTMLElement & {
      shadowRoot?: ShadowRoot | null;
    };
    if (rich?.shadowRoot) {
      const e =
        rich.shadowRoot.querySelector("div.ql-editor[contenteditable='true']") ||
        rich.shadowRoot.querySelector('[contenteditable="true"]');
      if (e instanceof HTMLElement && qlPred(e)) return e;
    }
  }

  const candidates = document.querySelectorAll(
    'div.ql-editor[contenteditable="true"], [contenteditable="true"]'
  );
  for (let i = candidates.length - 1; i >= 0; i--) {
    const el = candidates[i];
    if (!(el instanceof HTMLElement)) continue;
    if (el.classList.contains("ql-clipboard")) continue;
    if (!qlPred(el)) continue;
    if (
      el.closest(
        "footer, [role='search'], form, nav, header, [class*='input'], [class*='footer'], .text-input-field"
      )
    ) {
      return el;
    }
  }
  for (let i = candidates.length - 1; i >= 0; i--) {
    const el = candidates[i];
    if (!(el instanceof HTMLElement)) continue;
    if (el.classList.contains("ql-clipboard")) continue;
    if (qlPred(el)) return el;
  }
  return null;
}

fill.typescript:
/** Phase: fill — Gemini Trusted Types–safe Quill body fill. */
export function fillGeminiQuillEditor(editable: HTMLElement, text: string): void {
  editable.focus();
  editable.replaceChildren();
  const lines = text.split(/\r?\n/);
  for (const line of lines) {
    const p = document.createElement("p");
    p.textContent = line;
    editable.appendChild(p);
  }
  if (editable.childNodes.length === 0) {
    editable.appendChild(document.createElement("p")).appendChild(
      document.createElement("br")
    );
  }

  const opts = { bubbles: true, composed: true } as const;
  try {
    editable.dispatchEvent(
      new InputEvent("beforeinput", {
        ...opts,
        inputType: "insertFromPaste",
        data: text,
      })
    );
  } catch {
    /* older browsers */
  }
  editable.dispatchEvent(new Event("input", opts));
  editable.dispatchEvent(
    new InputEvent("input", { ...opts, inputType: "insertText", data: text })
  );
  editable.dispatchEvent(new Event("change", opts));
  editable.dispatchEvent(new KeyboardEvent("keyup", { ...opts, key: "a" }));
}

submit.typescript:
import {
  isProbablyVisible,
  lastMatchingElement,
  sleep,
  waitFor,
  waitForPaintTick,
} from "./domHelpers";

export function isGeminiSendButtonDisabled(btn: HTMLButtonElement): boolean {
  if (btn.disabled) return true;
  if (btn.getAttribute("aria-disabled") === "true") return true;
  if (btn.classList.contains("mat-mdc-button-disabled")) return true;
  return false;
}

export function queryGeminiSendButtonNearEditor(
  editable: HTMLElement
): HTMLButtonElement | null {
  const root =
    editable.closest("[data-node-type='input-area']") ??
    editable.closest("input-area-v2") ??
    editable.closest("fieldset.input-area-container");
  if (!root) return null;
  const prefer = root.querySelectorAll(
    "button.send-button.submit, button.send-button.has-input, button.send-button"
  );
  for (let i = prefer.length - 1; i >= 0; i--) {
    const b = prefer[i];
    if (b instanceof HTMLButtonElement) return b;
  }
  return null;
}

export function queryGeminiSendButton(): HTMLButtonElement | null {
  const composerScoped = [
    '[data-node-type="input-area"] button.send-button',
    "footer button.send-button",
    ".text-input-field button.send-button",
  ];
  for (const sel of composerScoped) {
    const el = lastMatchingElement(
      sel,
      (b) => b instanceof HTMLButtonElement && isProbablyVisible(b)
    );
    if (el instanceof HTMLButtonElement) return el;
  }

  const selectors = [
    "button.send-button.submit",
    'button.send-button[aria-label="Send message"]',
    "button.send-button",
    'button.submit[aria-label="Send message"]',
    'button[aria-label="Send message"]',
    'button[aria-label*="Send" i]',
  ];
  for (const sel of selectors) {
    const el = lastMatchingElement(
      sel,
      (b) => b instanceof HTMLButtonElement && isProbablyVisible(b)
    );
    if (el instanceof HTMLButtonElement) return el;
  }
  return null;
}

export function findGeminiSendButton(): HTMLButtonElement | null {
  return queryGeminiSendButton();
}

export async function waitForGeminiEnabledSendButton(
  timeoutMs: number,
  editable?: HTMLElement
): Promise<HTMLButtonElement | null> {
  return waitFor(() => {
    const b =
      (editable ? queryGeminiSendButtonNearEditor(editable) : null) ??
      queryGeminiSendButton();
    if (!b || isGeminiSendButtonDisabled(b)) return null;
    return b;
  }, timeoutMs);
}

/** Phase: submit — pointer synthesis + Enter for Angular Material. */
export async function submitGeminiComposer(
  editable: HTMLElement,
  btn: HTMLButtonElement
): Promise<void> {
  editable.focus();
  await sleep(16);
  btn.focus();
  await waitForPaintTick();

  const rect = btn.getBoundingClientRect();
  const cx = rect.left + Math.max(1, rect.width) / 2;
  const cy = rect.top + Math.max(1, rect.height) / 2;
  const base = {
    bubbles: true,
    cancelable: true,
    composed: true,
    clientX: cx,
    clientY: cy,
    view: window,
  } as const;
  let usedPointer = false;
  try {
    btn.dispatchEvent(
      new PointerEvent("pointerdown", {
        ...base,
        pointerId: 1,
        pointerType: "mouse",
        button: 0,
        buttons: 1,
      })
    );
    btn.dispatchEvent(
      new MouseEvent("mousedown", { ...base, button: 0, buttons: 1 })
    );
    btn.dispatchEvent(
      new PointerEvent("pointerup", {
        ...base,
        pointerId: 1,
        pointerType: "mouse",
        button: 0,
        buttons: 0,
      })
    );
    btn.dispatchEvent(
      new MouseEvent("mouseup", { ...base, button: 0, buttons: 0 })
    );
    btn.dispatchEvent(new MouseEvent("click", { ...base, button: 0 }));
    usedPointer = true;
  } catch {
    /* PointerEvent missing in very old engines */
  }
  if (!usedPointer) {
    btn.click();
  }

  await sleep(24);
  editable.focus();
  const ke = { bubbles: true, composed: true, cancelable: true } as const;
  editable.dispatchEvent(
    new KeyboardEvent("keydown", {
      ...ke,
      key: "Enter",
      code: "Enter",
      keyCode: 13,
      which: 13,
    })
  );
  editable.dispatchEvent(
    new KeyboardEvent("keyup", {
      ...ke,
      key: "Enter",
      code: "Enter",
      keyCode: 13,
      which: 13,
    })
  );
}

run_ask.typescript:
import { sleep, waitFor } from "./domHelpers";
import {
  collectGeminiModelReplyForPrompt,
  collectGeminiModelReplyGlobal,
  geminiCaptureKey,
  isGeminiMarkdownIdleForPrompt,
  normalizeGeminiChatPrompt,
  type GeminiAssistantCapture,
} from "./capture";
import { fillGeminiQuillEditor } from "./fill";
import { geminiPostToContent } from "./emit";
import { findGeminiEditableRoot } from "./resolveComposer";
import {
  findGeminiSendButton,
  isGeminiSendButtonDisabled,
  queryGeminiSendButton,
  queryGeminiSendButtonNearEditor,
  submitGeminiComposer,
  waitForGeminiEnabledSendButton,
} from "./submit";

/** Orchestrates resolve → fill → submit → wait_capture → emit. */
export async function runGeminiAsk(text: string): Promise<void> {
  const captureBase: Record<string, unknown> = {
    startedAt: new Date().toISOString(),
  };

  const editable = await waitFor(findGeminiEditableRoot, 20000);
  if (!editable) {
    geminiPostToContent({
      assistantHtml: "",
      assistantText: "",
      capture: { ...captureBase, ok: false, reason: "no_input" },
      page: { href: location.href, title: document.title },
    });
    return;
  }

  fillGeminiQuillEditor(editable, text);

  await sleep(120);
  let btn =
    (await waitForGeminiEnabledSendButton(12000, editable)) ??
    queryGeminiSendButtonNearEditor(editable) ??
    (await waitFor(findGeminiSendButton, 2000)) ??
    findGeminiSendButton();
  if (!btn) {
    geminiPostToContent({
      assistantHtml: "",
      assistantText: "",
      capture: { ...captureBase, ok: false, reason: "no_send_button" },
      page: { href: location.href, title: document.title },
    });
    return;
  }
  if (isGeminiSendButtonDisabled(btn)) {
    fillGeminiQuillEditor(editable, text);
    await sleep(200);
    btn =
      (await waitForGeminiEnabledSendButton(8000, editable)) ??
      queryGeminiSendButtonNearEditor(editable) ??
      queryGeminiSendButton() ??
      btn;
  }
  if (!btn || isGeminiSendButtonDisabled(btn)) {
    geminiPostToContent({
      assistantHtml: "",
      assistantText: "",
      capture: {
        ...captureBase,
        ok: false,
        reason: "send_button_stayed_disabled",
      },
      page: { href: location.href, title: document.title },
    });
    return;
  }
  const near = queryGeminiSendButtonNearEditor(editable);
  if (near && !isGeminiSendButtonDisabled(near)) {
    btn = near;
  }
  await submitGeminiComposer(editable, btn);

  let lastKey = "";
  let lastCapture: GeminiAssistantCapture = {
    assistantHtml: "",
    assistantText: "",
  };
  let stableTicks = 0;
  const maxTicks = 600;
  const pollMs = 200;
  const promptNorm = normalizeGeminiChatPrompt(text);
  const pickCapture = () =>
    promptNorm
      ? collectGeminiModelReplyForPrompt(text)
      : collectGeminiModelReplyGlobal();
  const pickIdle = () =>
    promptNorm ? isGeminiMarkdownIdleForPrompt(text) : false;

  for (let i = 0; i < maxTicks; i++) {
    await sleep(pollMs);
    const cap = pickCapture();
    const key = geminiCaptureKey(cap);
    if (key) lastCapture = cap;
    if (key && key === lastKey) stableTicks += 1;
    else {
      stableTicks = 0;
      lastKey = key;
    }
    const uiIdle = pickIdle();
    const needStable = uiIdle ? 2 : 4;
    if (stableTicks >= needStable && key.length > 0) {
      geminiPostToContent({
        assistantHtml: cap.assistantHtml,
        assistantText: cap.assistantText,
        capture: {
          ...captureBase,
          completedAt: new Date().toISOString(),
          stableTicks,
          pollTicks: i,
          uiIdle,
        },
        page: { href: location.href, title: document.title },
      });
      return;
    }
  }

  const finalCap = pickCapture();
  const use = geminiCaptureKey(finalCap) ? finalCap : lastCapture;
  geminiPostToContent({
    assistantHtml: use.assistantHtml,
    assistantText: use.assistantText,
    capture: {
      ...captureBase,
      completedAt: new Date().toISOString(),
      reason: "timeout_or_partial",
      pollTicks: maxTicks,
    },
    page: { href: location.href, title: document.title },
  });
}

wait_capture.typescript:
/** Phase: wait_capture — Gemini conversation / model-response DOM. */

export type GeminiAssistantCapture = {
  assistantHtml: string;
  assistantText: string;
};

function assistantRootToCapture(root: HTMLElement): GeminiAssistantCapture {
  return {
    assistantHtml: root.innerHTML?.trim() ?? "",
    assistantText: root.innerText?.trim() ?? "",
  };
}

export function geminiCaptureKey(c: GeminiAssistantCapture): string {
  return c.assistantHtml || c.assistantText;
}

function resolveAssistantMarkdownPanel(el: HTMLElement): HTMLElement | null {
  if (el.classList.contains("markdown")) return el;
  const inner = el.querySelector(
    '.markdown[aria-live="polite"], .markdown.markdown-main-panel, message-content .markdown, .markdown'
  );
  return inner instanceof HTMLElement ? inner : null;
}

function lastNonEmptyAssistantCapture(
  nodes: Iterable<Element>
): GeminiAssistantCapture {
  const empty: GeminiAssistantCapture = { assistantHtml: "", assistantText: "" };
  const list = Array.from(nodes);
  for (let i = list.length - 1; i >= 0; i--) {
    const el = list[i];
    if (!(el instanceof HTMLElement)) continue;
    const panel = resolveAssistantMarkdownPanel(el);
    if (!panel) continue;
    const cap = assistantRootToCapture(panel);
    if (geminiCaptureKey(cap)) return cap;
  }
  return empty;
}

export function normalizeGeminiChatPrompt(s: string): string {
  return s
    .trim()
    .replace(/\s+/g, " ")
    .toLowerCase();
}

function userQueryTextFromConversation(c: Element): string {
  const lines = c.querySelectorAll("user-query .query-text-line");
  const parts: string[] = [];
  for (const el of lines) {
    parts.push(el.textContent ?? "");
  }
  let raw = parts.join(" ").trim();
  if (!raw) {
    raw =
      c.querySelector("user-query .query-text")?.textContent?.trim() ?? "";
  }
  if (!raw) {
    raw = c.querySelector("user-query")?.textContent?.trim() ?? "";
  }
  return raw.replace(/\bYou said\b/gi, "").replace(/\s+/g, " ").trim();
}

function findConversationForPrompt(prompt: string): Element | null {
  const want = normalizeGeminiChatPrompt(prompt);
  if (!want) return null;
  const containers = document.querySelectorAll("div.conversation-container");
  for (let i = containers.length - 1; i >= 0; i--) {
    const c = containers[i];
    const got = normalizeGeminiChatPrompt(userQueryTextFromConversation(c));
    if (!got) continue;
    if (got === want) return c;
    if (want.length >= 4 && got.includes(want)) return c;
    if (got.length >= 4 && want.includes(got)) return c;
  }
  return null;
}

function assistantMarkdownRoot(mr: Element): HTMLElement | null {
  const polite = mr.querySelector('.markdown[aria-live="polite"]');
  if (polite instanceof HTMLElement) return polite;
  const panel = mr.querySelector(".markdown.markdown-main-panel");
  if (panel instanceof HTMLElement) return panel;
  const inner = mr.querySelector("message-content .markdown");
  if (inner instanceof HTMLElement) return inner;
  const mc = mr.querySelector("message-content");
  if (mc instanceof HTMLElement) return mc;
  return null;
}

export function collectGeminiModelReplyForPrompt(
  prompt: string
): GeminiAssistantCapture {
  const empty: GeminiAssistantCapture = { assistantHtml: "", assistantText: "" };
  const c = findConversationForPrompt(prompt);
  if (!c) return empty;
  const mr = c.querySelector("model-response");
  if (!mr) return empty;
  const root = assistantMarkdownRoot(mr);
  return root instanceof HTMLElement ? assistantRootToCapture(root) : empty;
}

export function isGeminiMarkdownIdleForPrompt(prompt: string): boolean {
  const c = findConversationForPrompt(prompt);
  if (!c) return false;
  const mr = c.querySelector("model-response");
  if (!mr) return false;
  const root = assistantMarkdownRoot(mr);
  if (!(root instanceof HTMLElement)) return false;
  return root.getAttribute("aria-busy") !== "true";
}

export function collectGeminiModelReplyGlobal(): GeminiAssistantCapture {
  const chains: string[] = [
    'model-response .markdown[aria-live="polite"]',
    "model-response message-content",
    '[class*="model-response-text"] .markdown[aria-live="polite"]',
    '[class*="model-response-text"] message-content',
    'message-content[class*="model-response"]',
  ];
  for (const sel of chains) {
    const cap = lastNonEmptyAssistantCapture(document.querySelectorAll(sel));
    if (geminiCaptureKey(cap)) return cap;
  }
  const shells = document.querySelectorAll('[class*="model-response-text"]');
  const fromShell = lastNonEmptyAssistantCapture(shells);
  if (geminiCaptureKey(fromShell)) return fromShell;
  return lastNonEmptyAssistantCapture(
    document.querySelectorAll("message-content")
  );
}

