import {
  isInHiddenAncestor,
  isProbablyVisible,
  sleep,
  waitForPaintTick,
} from "./domHelpers";

function findVisibleSubmitButton(
  form: HTMLFormElement | null
): HTMLButtonElement | null {
  if (!form) return null;
  for (const b of form.querySelectorAll('button[type="submit"]')) {
    if (!(b instanceof HTMLButtonElement)) continue;
    if (b.disabled) continue;
    if (isInHiddenAncestor(b)) continue;
    if (!isProbablyVisible(b)) continue;
    return b;
  }
  for (const b of form.querySelectorAll("button")) {
    if (!(b instanceof HTMLButtonElement)) continue;
    if (b.disabled) continue;
    if (isInHiddenAncestor(b)) continue;
    if (!isProbablyVisible(b)) continue;
    const al = (b.getAttribute("aria-label") || "").trim().toLowerCase();
    if (
      al === "submit" ||
      al === "提交" ||
      al.includes("send") ||
      al.includes("傳送")
    ) {
      return b;
    }
  }
  return null;
}

async function clickSubmitButton(
  composer: HTMLElement,
  btn: HTMLButtonElement
): Promise<void> {
  composer.focus();
  await sleep(20);
  btn.focus();
  await waitForPaintTick();
  const rect = btn.getBoundingClientRect();
  const cx = rect.left + Math.max(1, rect.width) / 2;
  const cy = rect.top + Math.max(1, rect.height) / 2;
  const base = {
    bubbles: true,
    cancelable: true,
    composed: true,
    clientX: cx,
    clientY: cy,
    view: window,
  } as const;
  try {
    btn.dispatchEvent(
      new PointerEvent("pointerdown", {
        ...base,
        pointerId: 1,
        pointerType: "mouse",
        button: 0,
        buttons: 1,
      })
    );
    btn.dispatchEvent(
      new MouseEvent("mousedown", { ...base, button: 0, buttons: 1 })
    );
    btn.dispatchEvent(
      new PointerEvent("pointerup", {
        ...base,
        pointerId: 1,
        pointerType: "mouse",
        button: 0,
        buttons: 0,
      })
    );
    btn.dispatchEvent(
      new MouseEvent("mouseup", { ...base, button: 0, buttons: 0 })
    );
    btn.dispatchEvent(new MouseEvent("click", { ...base, button: 0 }));
  } catch {
    btn.click();
  }
}

function dispatchModEnter(el: HTMLElement): void {
  el.focus();
  const isMac = /Mac|iPhone|iPod|iPad/i.test(navigator.platform);
  const base = { bubbles: true, composed: true, cancelable: true } as const;
  for (const type of ["keydown", "keypress", "keyup"] as const) {
    el.dispatchEvent(
      new KeyboardEvent(type, {
        ...base,
        key: "Enter",
        code: "Enter",
        keyCode: 13,
        which: 13,
        metaKey: isMac,
        ctrlKey: !isMac,
      })
    );
  }
}

function dispatchPlainEnter(el: HTMLElement): void {
  const base = { bubbles: true, composed: true, cancelable: true } as const;
  el.dispatchEvent(
    new KeyboardEvent("keydown", {
      ...base,
      key: "Enter",
      code: "Enter",
      keyCode: 13,
      which: 13,
    })
  );
}

/** Phase: submit — visible button or Mod+Enter / Enter. */
export async function submitGrokFilled(
  composer: HTMLElement,
  form: HTMLFormElement | null,
  _kind: "textarea" | "prose"
): Promise<void> {
  const btn = findVisibleSubmitButton(form);
  if (btn) {
    await clickSubmitButton(composer, btn);
    return;
  }
  await sleep(100);
  dispatchModEnter(composer);
  await sleep(80);
  dispatchPlainEnter(composer);
}

run_ask.typescript:
import { sleep, waitFor } from "./domHelpers";
import {
  collectGrokLatestAssistantPlain,
  grokStableTicksNeeded,
  isGrokAssistantBoilerplate,
  isLikelyGrokPreviewSnippet,
  normalizeGrokChat,
} from "./capture";
import { fillGrokProseMirror, fillGrokTextarea } from "./fill";
import { grokPostToContent } from "./emit";
import { pickGrokComposer } from "./resolveComposer";
import { submitGrokFilled } from "./submit";

export async function runGrokAsk(text: string): Promise<void> {
  const captureBase: Record<string, unknown> = {
    startedAt: new Date().toISOString(),
  };

  const picked = await waitFor(pickGrokComposer, 28000, 140);
  if (!picked) {
    grokPostToContent({
      assistantText: "",
      capture: { ...captureBase, ok: false, reason: "no_input" },
      page: { href: location.href, title: document.title },
    });
    return;
  }

  const { el: composer, kind, form } = picked;
  if (kind === "textarea") {
    fillGrokTextarea(composer as HTMLTextAreaElement, text);
  } else {
    fillGrokProseMirror(composer, text);
  }

  await sleep(kind === "prose" ? 450 : 200);

  const want = normalizeGrokChat(text);
  const before = collectGrokLatestAssistantPlain(want);
  await submitGrokFilled(composer, form, kind);
  let lastText = "";
  let stableTicks = 0;
  const maxTicks = 600;
  const pollMs = 200;

  for (let i = 0; i < maxTicks; i++) {
    await sleep(pollMs);
    let cur = collectGrokLatestAssistantPlain(want);
    if (isGrokAssistantBoilerplate(cur)) {
      cur = "";
    }
    if (!cur || cur === before) continue;
    if (want && normalizeGrokChat(cur) === want) continue;
    if (cur === lastText) stableTicks += 1;
    else {
      stableTicks = 0;
      lastText = cur;
    }
    const needStable = grokStableTicksNeeded(cur.length);
    const previewSnip = isLikelyGrokPreviewSnippet(text, cur);
    if (stableTicks >= needStable && cur.length > 0 && !previewSnip) {
      grokPostToContent({
        assistantText: cur,
        capture: {
          ...captureBase,
          completedAt: new Date().toISOString(),
          stableTicks,
          pollTicks: i,
        },
        page: { href: location.href, title: document.title },
      });
      return;
    }
  }

  let final = collectGrokLatestAssistantPlain(want);
  if (isGrokAssistantBoilerplate(final)) final = "";
  const use =
    final &&
    final !== before &&
    (!want || normalizeGrokChat(final) !== want)
      ? final
      : lastText;
  grokPostToContent({
    assistantText: use,
    capture: {
      ...captureBase,
      completedAt: new Date().toISOString(),
      reason: "timeout_or_partial",
      pollTicks: maxTicks,
    },
    page: { href: location.href, title: document.title },
  });
}

wait_capture.typescript:
/** Phase: wait_capture — `.response-content-markdown` + stability heuristics. */

import { pickGrokComposer } from "./resolveComposer";

function excludeComposerTree(): HTMLElement | null {
  const pick = pickGrokComposer();
  if (!pick) return null;
  if (pick.form) return pick.form;
  return pick.el.closest("footer");
}

function normalizeChat(s: string): string {
  return s.trim().replace(/\s+/g, " ");
}

function isUserMessageMarkdown(el: HTMLElement): boolean {
  const row = el.closest('div[id^="response-"]');
  if (!(row instanceof HTMLElement)) return false;
  return row.classList.contains("items-end");
}

function isInsideThinkingUi(el: HTMLElement): boolean {
  return !!el.closest(".thinking-container");
}

export function isGrokAssistantBoilerplate(text: string): boolean {
  const t = text.trim();
  if (!t) return true;
  const low = normalizeChat(t).toLowerCase();
  if (/^參考以下內容[:：]?\s*$/i.test(t)) return true;
  if (/^参考以下内容[:：]?\s*$/i.test(t)) return true;
  if (/^refer to the following content[:：]?\s*$/i.test(low)) return true;
  if (
    /user message only says/.test(low) &&
    /refer to the following/i.test(low)
  ) {
    return true;
  }
  if (/請提供您要我參考的內容/.test(t) && t.length < 200) return true;
  if (/请提供您要我参考的内容/.test(t) && t.length < 200) return true;
  if (
    /please provide (the )?content (you want|for me)/i.test(t) &&
    t.length < 200
  ) {
    return true;
  }
  return false;
}

export function collectGrokLatestAssistantPlain(promptNorm: string): string {
  const main = document.querySelector("main");
  if (!main) return "";
  const exclude = excludeComposerTree();

  const collectFrom = (root: ParentNode): HTMLElement[] => {
    const out: HTMLElement[] = [];
    for (const node of root.querySelectorAll(".response-content-markdown")) {
      if (!(node instanceof HTMLElement)) continue;
      if (exclude && exclude.contains(node)) continue;
      if (node.closest("form")) continue;
      if (isInsideThinkingUi(node)) continue;
      if (isUserMessageMarkdown(node)) continue;
      out.push(node);
    }
    return out;
  };

  const lastReply = document.querySelector("#last-reply-container");
  const inLast = lastReply ? collectFrom(lastReply) : [];
  const candidates =
    inLast.length > 0
      ? inLast
      : lastReply
        ? []
        : collectFrom(main);

  const score = (node: HTMLElement): number => {
    const inLastEl = !!(lastReply && lastReply.contains(node));
    const r = node.getBoundingClientRect();
    const top = Number.isFinite(r.top) ? r.top : 0;
    return (inLastEl ? 1e9 : 0) + top;
  };

  const sorted = [...candidates].sort((a, b) => score(b) - score(a));

  let best: HTMLElement | null = null;
  let bestScore = -Infinity;
  for (const node of sorted) {
    const t = (node.innerText || "").trim();
    if (t.length < 2) continue;
    if (promptNorm && normalizeChat(t) === promptNorm) continue;
    if (isGrokAssistantBoilerplate(t)) continue;
    const r = node.getBoundingClientRect();
    if (r.height < 4) continue;
    const s = score(node);
    if (s >= bestScore) {
      bestScore = s;
      best = node;
    }
  }
  return best ? (best.innerText || "").trim() : "";
}

export function isLikelyGrokPreviewSnippet(prompt: string, reply: string): boolean {
  if (reply.length >= 200) return false;
  const hasCjk = /[\u3040-\u30ff\u3400-\u9fff\uac00-\ud7af]/.test(prompt);
  if (!hasCjk) return false;
  const nonWs = reply.replace(/\s/g, "");
  if (!nonWs.length) return false;
  const nonAsciiRatio =
    nonWs.replace(/[\u0000-\u007f]/g, "").length / nonWs.length;
  return nonAsciiRatio < 0.15 && reply.length < 180;
}

export function grokStableTicksNeeded(replyLen: number): number {
  if (replyLen < 80) return 12;
  if (replyLen < 240) return 8;
  return 4;
}

export { normalizeChat as normalizeGrokChat };

